const raw = $input.first().json.choices[0].message.content || "";
let t = raw.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
t = t.replace(/\*\*(.+?)\*\*/g, "<b>$1</b>");
const footer = "\n\n<a href=\"https://t.me/+XXXXXXXXXXXX\">📲 Новинний канал | Підписатись</a>";
return [{ json: { text: t + footer } }];
